class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.container.style.width = '100%';
        this.container.style.height = '100%';
        this.container.style.display = 'flex';
        this.container.style.flexDirection = 'column';
        this.container.style.backgroundColor = '#f8fafc';
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        window.addEventListener('resize', () => this.resize());
        this.resize();
        this.update(initialInputs);
    }

    resize() {
        this.canvas.width = this.container.clientWidth * window.devicePixelRatio;
        this.canvas.height = this.container.clientHeight * window.devicePixelRatio;
        this.canvas.style.width = this.container.clientWidth + 'px';
        this.canvas.style.height = this.container.clientHeight + 'px';
        this.ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    }

    update(inputs) {
        const { speed, angle, height, gravity } = inputs;
        const rad = (angle * Math.PI) / 180;
        const vx = speed * Math.cos(rad);
        const vy = speed * Math.sin(rad);

        // Quadratic formula for time of flight: -0.5*g*t^2 + vy*t + h = 0
        const a = -0.5 * gravity;
        const b = vy;
        const c = height;
        const discriminant = Math.sqrt(b * b - 4 * a * c);
        const tFlight = (-b - discriminant) / (2 * a);
        const range = vx * tFlight;
        const tPeak = vy / gravity;
        const hMax = height + (vy > 0 ? (vy * vy) / (2 * gravity) : 0);

        this.draw(inputs, { vx, vy, tFlight, range, tPeak, hMax });
    }

    draw(inputs, stats) {
        const ctx = this.ctx;
        const w = this.canvas.width / window.devicePixelRatio;
        const h = this.canvas.height / window.devicePixelRatio;
        ctx.clearRect(0, 0, w, h);

        const padding = 60;
        const simWidth = w - padding * 2 - 250; // Leave space for panel
        const simHeight = h - padding * 2;

        // Scaling factor (auto-zoom based on trajectory size)
        const scaleX = simWidth / Math.max(stats.range * 1.1, 20);
        const scaleY = simHeight / Math.max(stats.hMax * 1.2, 20);
        const scale = Math.min(scaleX, scaleY);

        const originX = padding;
        const originY = h - padding;

        // Draw Ground
        ctx.beginPath();
        ctx.moveTo(0, originY);
        ctx.lineTo(w, originY);
        ctx.strokeStyle = '#94a3b8';
        ctx.lineWidth = 2;
        ctx.stroke();

        // Draw Trajectory Path
        ctx.beginPath();
        ctx.setLineDash([5, 5]);
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        for (let t = 0; t <= stats.tFlight; t += stats.tFlight / 100) {
            const tx = originX + (inputs.speed * Math.cos(inputs.angle * Math.PI / 180) * t) * scale;
            const ty = originY - (inputs.height + (inputs.speed * Math.sin(inputs.angle * Math.PI / 180) * t) - 0.5 * inputs.gravity * t * t) * scale;
            if (t === 0) ctx.moveTo(tx, ty);
            else ctx.lineTo(tx, ty);
        }
        ctx.stroke();
        ctx.setLineDash([]);

        // Draw Launch Point & Projectile
        ctx.fillStyle = '#ef4444';
        ctx.beginPath();
        ctx.arc(originX, originY - inputs.height * scale, 6, 0, Math.PI * 2);
        ctx.fill();

        // Draw Velocity Vectors
        const vectorScale = 2;
        ctx.beginPath();
        ctx.strokeStyle = '#10b981';
        ctx.lineWidth = 3;
        ctx.moveTo(originX, originY - inputs.height * scale);
        ctx.lineTo(originX + stats.vx * vectorScale, originY - inputs.height * scale - stats.vy * vectorScale);
        ctx.stroke();

        // Information Panel
        const panelX = w - 280;
        ctx.fillStyle = '#ffffff';
        ctx.shadowBlur = 10;
        ctx.shadowColor = 'rgba(0,0,0,0.1)';
        ctx.fillRect(panelX, 20, 260, h - 40);
        ctx.shadowBlur = 0;
        ctx.strokeStyle = '#e2e8f0';
        ctx.strokeRect(panelX, 20, 260, h - 40);

        ctx.fillStyle = '#1e293b';
        ctx.font = 'bold 16px Inter, sans-serif';
        ctx.fillText('Step-by-Step Solution', panelX + 20, 50);

        ctx.font = '13px Inter, sans-serif';
        let yOff = 85;
        const drawStep = (label, value) => {
            ctx.fillStyle = '#64748b';
            ctx.fillText(label, panelX + 20, yOff);
            ctx.fillStyle = '#3b82f6';
            ctx.font = 'bold 14px Inter, sans-serif';
            ctx.fillText(value, panelX + 20, yOff + 20);
            ctx.font = '13px Inter, sans-serif';
            yOff += 50;
        };

        drawStep('1. Horizontal Velocity (Vx)', `${stats.vx.toFixed(2)} m/s`);
        drawStep('2. Initial Vertical Velocity (Vy)', `${stats.vy.toFixed(2)} m/s`);
        drawStep('3. Time to Peak', `${stats.tPeak.toFixed(2)} s`);
        drawStep('4. Max Vertical Height (H)', `${stats.hMax.toFixed(2)} m`);
        drawStep('5. Total Time of Flight', `${stats.tFlight.toFixed(2)} s`);
        drawStep('6. Total Horizontal Range (R)', `${stats.range.toFixed(2)} m`);

        // Axis Labels
        ctx.fillStyle = '#94a3b8';
        ctx.font = '12px Inter, sans-serif';
        ctx.fillText('0m (Ground)', originX + 5, originY + 20);
        ctx.fillText(stats.range.toFixed(1) + 'm', originX + stats.range * scale - 20, originY + 20);
        ctx.save();
        ctx.translate(originX - 10, originY - inputs.height * scale);
        ctx.rotate(-Math.PI / 2);
        ctx.fillText('y = ' + inputs.height + 'm', 0, 0);
        ctx.restore();
    }
}
